-- Legacy import prepared from finance.xlsx
-- Scope: imports historical monthly aggregates up to and including 2026-06.
-- It intentionally skips 2026-07 and later, so current July 2026 app data is not overwritten.
-- Before running: if your app login email is different, change v_user_email below.

do $$
declare
  v_user_email text := 'paul.huebner13@gmail.com';
  v_user_id uuid;
  rec jsonb;
  bal_rec record;
  v_group_id uuid;
  v_category_id uuid;
  v_account_id uuid;
  v_from_account_id uuid;
  v_to_account_id uuid;
  v_closing_id uuid;
begin
  select id into v_user_id
  from auth.users
  where lower(email) = lower(v_user_email)
  order by created_at desc
  limit 1;

  if v_user_id is null then
    raise exception 'No Supabase auth user found for email %', v_user_email;
  end if;

  -- Accounts needed for historical month closings. Existing accounts are reused, current balances are not changed.
  for rec in select * from jsonb_array_elements('[{"name":"N26","type":"active","include":true,"is_default":true,"color":"#3258A8"},{"name":"Bank Austria","type":"active","include":true,"is_default":false,"color":"#16889A"},{"name":"Bargeld","type":"active","include":true,"is_default":false,"color":"#2F855A"},{"name":"Kaution Wohnung","type":"bound","include":false,"is_default":false,"color":"#B7791F"},{"name":"Scalable Capital","type":"investment","include":false,"is_default":false,"color":"#6D5BD0"}]'::jsonb) loop
    insert into public.accounts(user_id, name, type, include_in_available_net_worth, is_default, balance, color, is_active)
    select v_user_id, rec->>'name', rec->>'type', (rec->>'include')::boolean, (rec->>'is_default')::boolean, 0, rec->>'color', true
    where not exists (
      select 1 from public.accounts a
      where a.user_id = v_user_id and lower(a.name) = lower(rec->>'name')
    );
  end loop;

  -- Category groups needed for historical monthly aggregates. Existing groups are reused.
  for rec in select * from jsonb_array_elements('[{"kind":"expense","name":"Wohnen","color":"#f97316","sort_order":10,"period":"monthly"},{"kind":"expense","name":"Leben","color":"#eab308","sort_order":20,"period":"daily"},{"kind":"expense","name":"Mobilität","color":"#22c55e","sort_order":30,"period":"daily"},{"kind":"expense","name":"Kommunikation & Abos","color":"#3258a8","sort_order":40,"period":"monthly"},{"kind":"expense","name":"Versicherungen","color":"#8b5cf6","sort_order":50,"period":"monthly"},{"kind":"expense","name":"Notwendigkeiten","color":"#14b8a6","sort_order":60,"period":"daily"},{"kind":"expense","name":"Freizeit","color":"#facc15","sort_order":70,"period":"daily"},{"kind":"expense","name":"Ausgehen","color":"#ef4444","sort_order":80,"period":"daily"},{"kind":"investment","name":"Investieren","color":"#6D5BD0","sort_order":90,"period":"monthly"},{"kind":"income","name":"Einnahmen","color":"#0F766E","sort_order":100,"period":"monthly"}]'::jsonb) loop
    insert into public.category_groups(user_id, kind, name, average_monthly_budget, budget_period, color, sort_order, is_active)
    select v_user_id, rec->>'kind', rec->>'name', 0, rec->>'period', rec->>'color', (rec->>'sort_order')::int, true
    where not exists (
      select 1 from public.category_groups g
      where g.user_id = v_user_id and lower(g.name) = lower(rec->>'name') and g.kind = rec->>'kind'
    );
  end loop;

  -- Subcategories needed for historical monthly aggregates. Existing subcategories are reused.
  for rec in select * from jsonb_array_elements('[{"group":"Wohnen","name":"Heizung","sort_order":10,"period":"monthly"},{"group":"Wohnen","name":"Internet","sort_order":20,"period":"monthly"},{"group":"Wohnen","name":"Miete","sort_order":30,"period":"monthly"},{"group":"Wohnen","name":"Sonstiges","sort_order":40,"period":"daily"},{"group":"Wohnen","name":"Strom","sort_order":50,"period":"monthly"},{"group":"Wohnen","name":"Wasser","sort_order":60,"period":"monthly"},{"group":"Leben","name":"Drogerie","sort_order":10,"period":"daily"},{"group":"Leben","name":"Essen","sort_order":20,"period":"daily"},{"group":"Leben","name":"Friseur","sort_order":30,"period":"daily"},{"group":"Leben","name":"Gesundheit","sort_order":40,"period":"daily"},{"group":"Leben","name":"Lebensmittel","sort_order":50,"period":"daily"},{"group":"Leben","name":"Sonstiges","sort_order":60,"period":"daily"},{"group":"Mobilität","name":"Jahreskarte","sort_order":10,"period":"daily"},{"group":"Mobilität","name":"Sonstiges","sort_order":20,"period":"daily"},{"group":"Kommunikation & Abos","name":"ChatGPT","sort_order":10,"period":"monthly"},{"group":"Kommunikation & Abos","name":"F1","sort_order":20,"period":"monthly"},{"group":"Kommunikation & Abos","name":"Google","sort_order":30,"period":"monthly"},{"group":"Kommunikation & Abos","name":"Handy","sort_order":40,"period":"daily"},{"group":"Kommunikation & Abos","name":"Handyvertrag","sort_order":50,"period":"monthly"},{"group":"Kommunikation & Abos","name":"Laptop/Elektronik","sort_order":60,"period":"daily"},{"group":"Kommunikation & Abos","name":"Sonstiges","sort_order":70,"period":"daily"},{"group":"Kommunikation & Abos","name":"Spotify","sort_order":80,"period":"monthly"},{"group":"Versicherungen","name":"Berufsunfähigkeit","sort_order":10,"period":"monthly"},{"group":"Versicherungen","name":"Zusatzversicherung","sort_order":20,"period":"monthly"},{"group":"Notwendigkeiten","name":"Anschaffungen","sort_order":10,"period":"daily"},{"group":"Notwendigkeiten","name":"Geschenke","sort_order":20,"period":"daily"},{"group":"Notwendigkeiten","name":"Gym","sort_order":30,"period":"monthly"},{"group":"Notwendigkeiten","name":"Kleidung","sort_order":40,"period":"daily"},{"group":"Notwendigkeiten","name":"Sonstiges","sort_order":50,"period":"daily"},{"group":"Notwendigkeiten","name":"Sport","sort_order":60,"period":"daily"},{"group":"Notwendigkeiten","name":"TC","sort_order":70,"period":"monthly"},{"group":"Freizeit","name":"Aktivitäten","sort_order":10,"period":"daily"},{"group":"Freizeit","name":"Restaurant","sort_order":20,"period":"daily"},{"group":"Freizeit","name":"Sonstiges","sort_order":30,"period":"daily"},{"group":"Freizeit","name":"Tickets","sort_order":40,"period":"daily"},{"group":"Freizeit","name":"Urlaub","sort_order":50,"period":"daily"},{"group":"Freizeit","name":"Wetten","sort_order":60,"period":"daily"},{"group":"Einnahmen","name":"Gehalt","sort_order":10,"period":"monthly"},{"group":"Einnahmen","name":"Nebenjob","sort_order":20,"period":"monthly"},{"group":"Einnahmen","name":"Rückzahlung","sort_order":30,"period":"monthly"},{"group":"Einnahmen","name":"Sonstiges","sort_order":40,"period":"daily"},{"group":"Einnahmen","name":"Taschengeld","sort_order":50,"period":"monthly"},{"group":"Investieren","name":"ETF","sort_order":10,"period":"monthly"}]'::jsonb) loop
    select id into v_group_id
    from public.category_groups
    where user_id = v_user_id and lower(name) = lower(rec->>'group')
    order by created_at asc
    limit 1;

    if v_group_id is not null then
      insert into public.categories(user_id, group_id, name, average_monthly_budget, budget_period, sort_order, is_active)
      select v_user_id, v_group_id, rec->>'name', 0, rec->>'period', (rec->>'sort_order')::int, true
      where not exists (
        select 1 from public.categories c
        where c.user_id = v_user_id and c.group_id = v_group_id and lower(c.name) = lower(rec->>'name')
      );
    end if;
  end loop;

