      rec->>'month',
      (rec->>'debt_net_value')::numeric,
      (rec->>'comparable_value')::numeric,
      now()
    )
    on conflict (user_id, month) do nothing;

    select id into v_closing_id
    from public.month_closings
    where user_id = v_user_id and month = rec->>'month'
    limit 1;

    if v_closing_id is not null then
      for bal_rec in select * from jsonb_each_text(rec->'balances') loop
        select id into v_account_id
        from public.accounts
        where user_id = v_user_id and lower(name) = lower(bal_rec.key)
        order by created_at asc
        limit 1;

        if v_account_id is not null then
          insert into public.month_closing_balances(closing_id, account_id, actual_balance)
          values (v_closing_id, v_account_id, bal_rec.value::numeric)
          on conflict (closing_id, account_id) do nothing;
        end if;
      end loop;
    end if;
  end loop;

