nt":25.09,"group":"Kommunikation & Abos","category":"Sonstiges","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":24.9,"group":"Notwendigkeiten","category":"Gym","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":15.0,"group":"Notwendigkeiten","category":"Sport","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":27.0,"group":"Notwendigkeiten","category":"Geschenke","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":520.08,"group":"Notwendigkeiten","category":"Sonstiges","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":12.9,"group":"Freizeit","category":"Aktivitäten","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":918.43,"group":"Freizeit","category":"Urlaub","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":60.0,"group":"Freizeit","category":"Wetten","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"},{"date":"2026-06-01","type":"expense","amount":18.0,"group":"Freizeit","category":"Sonstiges","note":"Legacy Import finance.xlsx · Monatswert","account":"N26"}]'::jsonb) loop
    select id into v_group_id
    from public.category_groups
    where user_id = v_user_id and lower(name) = lower(rec->>'group') and kind = case when rec->>'type' = 'investment' then 'investment' when rec->>'type' = 'income' then 'income' else 'expense' end
    order by created_at asc
    limit 1;

    select id into v_category_id
    from public.categories
    where user_id = v_user_id and group_id = v_group_id and lower(name) = lower(rec->>'category')
    order by created_at asc
    limit 1;

    if rec->>'type' in ('income','expense') then
      select id into v_account_id
      from public.accounts
      where user_id = v_user_id and lower(name) = lower(coalesce(rec->>'account','N26'))
      order by created_at asc
      limit 1;

      if v_group_id is not null and v_account_id is not null then
        insert into public.transactions(user_id, type, amount, date, account_id, group_id, category_id, note)
        select v_user_id, rec->>'type', (rec->>'amount')::numeric, (rec->>'date')::date, v_account_id, v_group_id, v_category_id, rec->>'note'
        where not exists (
          select 1 from public.transactions t
          where t.user_id = v_user_id
            and t.date = (rec->>'date')::date
            and t.type = rec->>'type'
            and t.amount = (rec->>'amount')::numeric
            and t.group_id = v_group_id
            and coalesce(t.category_id, '00000000-0000-0000-0000-000000000000'::uuid) = coalesce(v_category_id, '00000000-0000-0000-0000-000000000000'::uuid)
            and coalesce(t.note,'') = coalesce(rec->>'note','')
        );
      end if;
    elsif rec->>'type' = 'investment' then
      select id into v_from_account_id
      from public.accounts
      where user_id = v_user_id and lower(name) = lower(coalesce(rec->>'from_account','N26'))
      order by created_at asc
      limit 1;

      select id into v_to_account_id
      from public.accounts
      where user_id = v_user_id and lower(name) = lower(coalesce(rec->>'to_account','Scalable Capital'))
      order by created_at asc
      limit 1;

      if v_group_id is not null and v_from_account_id is not null and v_to_account_id is not null then
        insert into public.transactions(user_id, type, amount, date, from_account_id, to_account_id, group_id, category_id, note)
        select v_user_id, 'investment', (rec->>'amount')::numeric, (rec->>'date')::date, v_from_account_id, v_to_account_id, v_group_id, v_category_id, rec->>'note'
        where not exists (
          select 1 from public.transactions t
          where t.user_id = v_user_id
            and t.date = (rec->>'date')::date
            and t.type = 'investment'
            and t.amount = (rec->>'amount')::numeric
            and coalesce(t.note,'') = coalesce(rec->>'note','')
        );
      end if;
    end if;
  end loop;

  raise notice 'Legacy import complete for user %. Inserted/reused % historical closings and % monthly aggregate transaction rows.',
    v_user_email, 49, 545;
end $$;
